changeSet.sql:
CREATE TABLE IF NOT EXISTS notebooks.notebook_ai_context (
    notebook_id uuid PRIMARY KEY,
    owner_id uuid NOT NULL,
    context jsonb NOT NULL DEFAULT '[]'::jsonb,
    summary text NOT NULL DEFAULT '',
    history_count int NOT NULL DEFAULT 0 CHECK (history_count >= 0),
    updated_at timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS notebook_ai_context_owner_idx
    ON notebooks.notebook_ai_context(owner_id);
